import openpyxl
wb = openpyxl.load_workbook('input.xlsx')
ws = wb['Sheet1']
print('Dimensions:', ws.dimensions)
for row in ws.iter_rows(min_row=1, max_row=20, max_col=10, values_only=False):
    for cell in row:
        if cell.value is not None or cell.coordinate.startswith('E'):
            print(f'{cell.coordinate}: value={cell.value!r}, type={type(cell.value).__name__}')
